async (params, browser) => {
  // Open page
  await browser.open(`https://www.strava.com/segments/${params.segment_id}`)

  // Wait for content
  await browser.waitForSelector('h1, [class*="Segment"], .segment-heading', 15000)

  // Let page render
  await browser.wait(2500)

  // Scroll for more
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(2000)

  // Extract data
  const page_data = await browser.evaluate(`const name = document.querySelector('h1, [class*="SegmentName"]')?.textContent?.trim()||''; const stats = {}; document.querySelectorAll('[class*="Stat"], .stat-row, .segment-stats span').forEach(el => { const text = el.textContent.trim(); if(text.length<60) { const parts = text.split(':').map(s=>s.trim()); if(parts.length===2) stats[parts[0].toLowerCase()]=parts[1]; } }); const lb = Array.from(document.querySelectorAll('table tbody tr, [class*="leaderboard"] li')).slice(0,20).map((row,i) => { const cells = Array.from(row.querySelectorAll('td')).map(c=>c.textContent.trim()); const link = row.querySelector('a'); return { rank: i+1, athlete: link?link.textContent.trim():'', data: cells.slice(0,5) }; }); return { segment_id: '' + params.segment_id + '', name, stats, leaderboard: lb, url: window.location.href }`)

  return page_data
}
